/**
 * Apollo 11 skin — full data embedded.
 * secondaryPatterns: engine trigger functions are re-attached on import.
 */
import { SECONDARY_PATTERNS as ENGINE_SP } from '../engine';

function withTriggers(patterns) {
  const out = {};
  Object.keys(patterns).forEach(k => {
    out[k] = { ...patterns[k] };
    if (ENGINE_SP[k]?.trigger) out[k].trigger = ENGINE_SP[k].trigger;
  });
  return out;
}

const DATA = {"id":"apollo_11","name":"Trajectory · Apollo 11","tagline":"1969. Mission Control. Three days to the Moon.","description":"Set inside the Mission Operations Control Room before and during Apollo 11 — with Katherine Johnson as your quiet north star, and Flight Director Bryce Calhoun as the pressure system you have to navigate.","theme":{"--amber":"#fc3d21","--amber-bright":"#ff6644","--amber-deep":"#c01a00","--amber-glow":"rgba(252, 61, 33, 0.35)","--brand-orange":"#fc3d21","--brand-tangerine":"#ff6b00","--brand-yellow":"#feab2b","--bg":"#070914","--bg-deep":"#040611","--panel":"#0b1326","--ink":"#f4ecdb","--ink-soft":"#d6cdb9","--ink-mute":"#b3a994","--ink-label":"#e6dfd1","--ink-dim":"#6b6354","--serif":"'DM Serif Display', 'Cormorant Garamond', Georgia, serif","--sans":"'Inter', sans-serif","fontImport":"https://fonts.googleapis.com/css2?family=DM+Serif+Display:ital@0;1&family=Inter:wght@300;400;500;600&display=swap"},"characters":{"commander":"Flight Director Bryce Calhoun","mentor":"Katherine Johnson"},"bodyClasses":[],"scenes":[{"type":"landing","location":"Houston · 16 July 1969","locationLabel":"HOUSTON · MISSION OPS · INBOUND","title":["Trajectory","·","Apollo","<em>11</em>"],"sub":"An assessment of how you think, decide, and lead when pressure enters the room","note":"Set inside Mission Control on the eve of the moon landing — to bypass familiar assumptions and reveal the pattern beneath","cta":"Take your console","duration":12000},{"type":"intake","locationLabel":"OPERATIONS PERSONNEL · CONFIDENTIAL","eyebrow":"Before we begin","title":"Sign in to Mission Operations.","sub":"Used to address you correctly through the mission and to render your console portrait."},{"type":"crawl","locationLabel":"PROLOGUE · CHANNEL OPEN","preamble":"July 1969 · Houston · Mission Operations","title":["Trajectory","Apollo","Eleven"],"episode":"Prologue · Mission Control","paragraphs":["It is a time of acceleration. A decade-long sprint has brought a nation, its engineers, and its mathematicians to the launch pad. Old certainties — patience, redundancy, the very meaning of safety — are being asked to bend.","In the shadow of the launch window, Mission Operations has summoned one rare voice. The Flight Director believes {{firstName}} can think clearly when others panic. The mission does not lack plans. It lacks people who can hold the line when those plans fail.","Flight Director Bryce Calhoun has risen to push the schedule through. He waits for {{firstName}} on the Mission Operations Control Room floor. He has already begun to choose...."],"duration":28200,"crawlStyle":"briefing","countdown":"T - 00:38:00:00 · GO FOR PROLOGUE"},{"type":"narrative","location":"Houston · MOCR","locationLabel":"HOUSTON · MISSION OPERATIONS CONTROL ROOM","eyebrow":"Act One · The Briefing","artId":"summonsHerald","layout":"disc-left","body":["The","window","is","narrowing."],"bodyAfter":["Systems are flagging. Engineers hesitate. The trajectory team is asking for another check.","You have been summoned, {{firstName}} — because you are believed to think clearly when others panic."],"duration":8500},{"type":"narrative-scene","location":"Coruscant · Council Chamber","locationLabel":"FLIGHT DIRECTOR BRYCE CALHOUN","artId":"councilChamber","quote":"\"The schedule does not lack engineers. It lacks people who can think clearly when those plans fail.\"","speaker":"Flight Director Bryce Calhoun","layout":"disc-right","duration":9000},{"type":"question","kind":"rating","location":"Coruscant · Council Chamber","locationLabel":"Q01 · UNDERSTAND SELF","practice":"Understand Self","setup":"Calhoun studies you. The console floor goes quiet. You feel the weight of being watched — by him, and by yourself.","prompt":"When pressure rises, I am aware of how my thinking and behaviour are beginning to change.","labels":["Strongly disagree","Disagree","Neutral","Agree","Strongly agree"],"scoring":[{"understand_self":0},{"understand_self":25},{"understand_self":50},{"understand_self":75},{"understand_self":100}]},{"type":"question","kind":"mc","locationLabel":"Q02 · MASTER EMOTIONS","practice":"Master Emotions","setup":"A junior controller is dressed down in front of the whole row. The room goes still. Heat rises in your chest.","prompt":"In the moment, what do you most notice happening inside you?","options":[{"copy":"A clean composure — I detach from the heat and keep the situation orderly.","score":{"master_emotions":35,"detachment_pressure":55}},{"copy":"A defensive impulse to step in immediately and reassert control of the room.","score":{"master_emotions":25,"control_bias":45}},{"copy":"A flash of anger or disappointment that I can name, but not yet act on cleanly.","score":{"master_emotions":60,"understand_self":50}},{"copy":"A steady warmth and a clear breath — I feel the reaction, choose how to respond, and act.","score":{"master_emotions":95,"understand_self":70,"embed_practices":50}},{"copy":"A blankness — I freeze, and I notice the freeze itself.","score":{"master_emotions":35,"understand_self":60}},{"copy":"I leave the console emotionally before my body does.","score":{"master_emotions":30,"detachment_pressure":65,"understand_self":25}}]},{"type":"question","kind":"rating","locationLabel":"Q03 · EMBED PRACTICES","practice":"Embed Practices","setup":"Between shifts the corridor empties. There is a single moment of stillness before the next sim.","prompt":"I have daily rituals — reflection, journaling, deliberate pauses — that I rely on to stay aware of myself under load.","labels":["Strongly disagree","Rarely","Sometimes","Often","It is part of how I live"],"scoring":[{"embed_practices":5},{"embed_practices":30},{"embed_practices":55},{"embed_practices":80},{"embed_practices":100}]},{"type":"narrative-scene","location":"Coruscant · Lower Corridor","locationLabel":"FLIGHT DIRECTOR BRYCE CALHOUN","artId":"fracturedCity","quote":"\"We are rebuilding the country's nerve. But people confuse caution with weakness. Tell me — what would you do first?\"","speaker":"Flight Director Bryce Calhoun","layout":"disc-left","duration":9000},{"type":"question","kind":"ranking","locationLabel":"Q04 · BE FUTURE-FOCUSED","practice":"Be Future-Focused","setup":"On the screen above the consoles, a destabilising telemetry trace. Engineers swear quietly. Calhoun waits.","prompt":"You are asked to stabilise a launch system flagging anomalies. Rank these priorities from first to last.","items":[{"label":"Understand the root causes before acting","score":{"future_focused":80,"think_critically":70,"be_curious":60}},{"label":"Build the long-term safety governance that prevents recurrence","score":{"future_focused":100,"collaborate_inclusively":55}},{"label":"Restore immediate operational control","score":{"act_decisively":70,"manage_uncertainty":35,"control_bias":40}},{"label":"Secure the most senior decision-makers so the launch holds","score":{"influence_effortlessly":60,"control_bias":35,"moral_drift":20}}],"weights":[1,0.65,0.35,0.05]},{"type":"narrative","locationLabel":"BUILDING 16 · THE COMPUTERS ROOM","eyebrow":"Act Two · The Computers","artId":"chaoticCouncil","layout":"disc-right","body":["You","enter","the","computers","room."],"bodyAfter":["Women at long desks. Slide rules. Mechanical calculators. Pages of trajectories.","Three mathematicians are arguing over a calculation. Calhoun says nothing. He watches you instead."],"duration":7500},{"type":"question","kind":"mc","locationLabel":"Q05 · LISTEN DEEPLY","practice":"Listen Deeply","setup":"Three mathematicians. One is silent — staring at her sheet. Another is shouting numbers. A third keeps glancing at the door.","prompt":"What do you do first?","options":[{"copy":"Step in and direct the conversation toward a clear next step.","score":{"act_decisively":45,"influence_effortlessly":35,"listen_deeply":15,"control_bias":40}},{"copy":"Stay quiet and observe — track who speaks, who avoids, who repeats themselves.","score":{"listen_deeply":90,"understand_self":55,"think_critically":50}},{"copy":"Ask each one a specific clarifying question, especially the silent one.","score":{"listen_deeply":80,"be_curious":85,"collaborate_inclusively":55}},{"copy":"Align them quickly around a shared answer to halt the back-and-forth.","score":{"influence_effortlessly":70,"collaborate_inclusively":45,"listen_deeply":30}},{"copy":"Mirror back what I am hearing beneath the words — fear, exhaustion, blame.","score":{"listen_deeply":95,"master_emotions":60,"collaborate_inclusively":60}},{"copy":"Defer until I can speak with each of them at her desk individually.","score":{"think_critically":45,"listen_deeply":35,"act_decisively":25}}]},{"type":"question","kind":"rating","locationLabel":"Q06 · LISTEN DEEPLY","practice":"Listen Deeply","setup":"Calhoun leans toward your ear. \"Look at the silent one,\" he murmurs. \"What is she telling you that the others are not?\"","prompt":"When conversations become chaotic, my instinct is to take control quickly — rather than stay present and read the pattern.","labels":["Strongly disagree","Disagree","Neutral","Agree","Strongly agree"],"scoring":[{"listen_deeply":100,"master_emotions":80,"control_bias":0},{"listen_deeply":75,"master_emotions":65,"control_bias":10},{"listen_deeply":50,"master_emotions":50,"control_bias":25},{"listen_deeply":25,"master_emotions":35,"control_bias":55},{"listen_deeply":10,"master_emotions":20,"control_bias":80}]},{"type":"question","kind":"mc","locationLabel":"Q07 · BE CURIOUS","practice":"Be Curious","setup":"One mathematician hands you a half-page of working — a derivation using a method you have never seen. \"This is what the disagreement is really about,\" she says.","prompt":"How do you respond to the unfamiliar method?","options":[{"copy":"Politely set it aside — the method is not the priority right now.","score":{"be_curious":15,"act_decisively":35}},{"copy":"Read it through, then ask three questions about what it does and where it came from.","score":{"be_curious":95,"listen_deeply":60,"think_critically":50}},{"copy":"Acknowledge it and promise to come back to it after the immediate decision is resolved.","score":{"be_curious":50,"act_decisively":45}},{"copy":"Ask her to walk me through it, slowly, before I respond to anything else in the room.","score":{"be_curious":100,"listen_deeply":80,"collaborate_inclusively":50}},{"copy":"Recognise the technique from my training and reference it back to her authoritatively.","score":{"influence_effortlessly":40,"be_curious":25,"control_bias":30}},{"copy":"Notice my reaction to not-knowing, and stay with the discomfort before responding.","score":{"be_curious":85,"understand_self":70,"master_emotions":55}}]},{"type":"narrative-scene","locationLabel":"TRACKING NETWORK · TELEMETRY DROPOUT","artId":"convoyArc","quote":"\"We commit now. Or we wait.\"","speaker":"Flight Director Bryce Calhoun","layout":"disc-right","duration":7500},{"type":"question","kind":"mc","locationLabel":"Q08 · MANAGE UNCERTAINTY","practice":"Manage Uncertainty","setup":"A tracking station has lost telemetry on the upper stage. You have 30% of the picture. You have minutes.","prompt":"What do you choose?","options":[{"copy":"Commit immediately with what I have — momentum matters more than completeness.","score":{"act_decisively":80,"manage_uncertainty":65,"control_bias":25}},{"copy":"Hold until I can confirm one critical telemetry point.","score":{"think_critically":55,"manage_uncertainty":20,"act_decisively":15}},{"copy":"Delegate the call to the station chief closest to the data.","score":{"collaborate_inclusively":70,"act_decisively":35,"manage_uncertainty":40}},{"copy":"Split the call — partial action on what I know, hold reserve for what I don't.","score":{"think_critically":70,"manage_uncertainty":80,"unlock_creativity":55,"act_decisively":60}},{"copy":"Make the smallest reversible move, then re-read the situation.","score":{"manage_uncertainty":95,"think_critically":65,"act_decisively":55}},{"copy":"Refuse the false choice and ask what assumptions are forcing it.","score":{"think_critically":90,"be_curious":70,"manage_uncertainty":60}}]},{"type":"question","kind":"rating","locationLabel":"Q09 · MANAGE UNCERTAINTY","practice":"Manage Uncertainty","setup":"Calhoun watches your face for the half-second of doubt before you answer. He has seen this moment in a hundred consoles.","prompt":"I am comfortable making high-stakes decisions without full information.","labels":["Strongly disagree","Disagree","Sometimes","Agree","Strongly agree"],"scoring":[{"manage_uncertainty":10,"act_decisively":10},{"manage_uncertainty":30,"act_decisively":30},{"manage_uncertainty":55,"act_decisively":50},{"manage_uncertainty":80,"act_decisively":75},{"manage_uncertainty":100,"act_decisively":85,"control_bias":15}]},{"type":"narrative","locationLabel":"BUILDING 4 · POST-SIMULATION DEBRIEF","eyebrow":"Act Three · The Anomaly","artId":"aftermathMedbay","layout":"disc-left","body":["The","sim","is","over.","But","at","a","cost."],"bodyAfter":["A miscalculation. A spacecraft lost on the screen. Engineers ashen.","Calhoun remains calm. \"Necessary,\" he says. \"We learn from this.\" You feel something shift."],"duration":8000,"variants":{"leaning_hale":{"bodyAfter":["Collateral damage. Civilian loss.","Hale remains calm. \"Necessary,\" he says — and you find yourself almost agreeing before you have asked the question."]},"resisting_hale":{"bodyAfter":["Collateral damage. Civilian loss.","Hale remains calm. \"Necessary,\" he says. You do not look away from him."]}}},{"type":"question","kind":"mc","locationLabel":"Q10 · MASTER EMOTIONS","practice":"Master Emotions","setup":"You stand in the debrief room. A young engineer's hands are shaking. A list of fault signatures scrolls on the screen. Calhoun waits at the door.","prompt":"In moments with heavy consequence, you most often:","options":[{"copy":"Stay composed and move forward — the mission needs me functional now.","score":{"master_emotions":65,"act_decisively":50,"detachment_pressure":45}},{"copy":"Pause, reflect deeply, name what I feel, and only act once I have processed it.","score":{"master_emotions":90,"understand_self":80,"embed_practices":50}},{"copy":"Question the decision afterwards — was it really the right call?","score":{"understand_self":70,"think_critically":60,"master_emotions":50}},{"copy":"Create deliberate distance from the emotion to think clearly.","score":{"master_emotions":40,"detachment_pressure":85,"moral_drift":25}},{"copy":"Sit with the people most affected before I sit with anything else.","score":{"master_emotions":75,"collaborate_inclusively":70,"listen_deeply":65}},{"copy":"Channel the weight into a clearer commitment about what I will not do again.","score":{"master_emotions":80,"future_focused":60,"understand_self":65}}]},{"type":"question","kind":"mc","locationLabel":"Q11 · THINK CRITICALLY","practice":"Think Critically","setup":"You replay the sim. Three different telemetry briefings. Three different versions of what was true. One of them was the one Calhoun handed you first.","prompt":"You suspect a troubling pattern in how decisions are being framed for you. What do you do?","options":[{"copy":"Challenge it directly in the next flight readiness review.","score":{"act_decisively":65,"influence_effortlessly":45,"master_emotions":40}},{"copy":"Quietly gather evidence across several decisions before raising anything.","score":{"think_critically":95,"manage_uncertainty":65,"understand_self":45}},{"copy":"Run a small experiment — frame the next briefing differently and see what happens.","score":{"think_critically":80,"unlock_creativity":60,"influence_effortlessly":45}},{"copy":"Set it aside — pattern recognition under stress is unreliable.","score":{"collaborate_inclusively":10,"moral_drift":40,"control_bias":20}},{"copy":"Share my hypothesis with one trusted colleague and ask them to challenge it.","score":{"think_critically":85,"collaborate_inclusively":70,"understand_self":50}},{"copy":"Ask three different telemetry sources the same question and triangulate.","score":{"think_critically":90,"be_curious":70}}]},{"type":"question","kind":"rating","locationLabel":"Q12 · BE CURIOUS","practice":"Be Curious","setup":"A mathematician from a discipline you know nothing about — orbital mechanics, manual integration by hand — offers to teach you her model of trajectory error. It will take three evenings.","prompt":"When I encounter an idea that does not fit my model of the world, my first impulse is to lean in, not push back.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"be_curious":5},{"be_curious":30},{"be_curious":55},{"be_curious":80},{"be_curious":100}]},{"type":"midpoint","locationLabel":"KATHERINE JOHNSON'S OFFICE · INTERLUDE · 01 / 03","eyebrow":"Interlude · Katherine","intro":"You step out of the MOCR. Down a quiet corridor, a door is open. Katherine Johnson is at her desk, slide rule in hand. She does not ask you to sit. She does not ask you to answer aloud. She asks you three questions, one at a time. Write only what is true.","showIntro":true,"prompt":"What are you noticing about how you are <em>thinking</em>?","placeholder":"The shape your thoughts have been taking…","hint":"A line, a phrase, an image — whatever is true right now.","key":"reflect_midpoint_thinking"},{"type":"midpoint","locationLabel":"KATHERINE JOHNSON'S OFFICE · INTERLUDE · 02 / 03","eyebrow":"Interlude · Katherine","showIntro":false,"prompt":"What are you noticing about how you are <em>feeling</em>?","placeholder":"Name it without judging it…","hint":"Whatever it is — Katherine is not surprised.","key":"reflect_midpoint_feeling"},{"type":"midpoint","locationLabel":"KATHERINE JOHNSON'S OFFICE · INTERLUDE · 03 / 03","eyebrow":"Interlude · Katherine","showIntro":false,"prompt":"What are you noticing about how you are <em>behaving</em>?","placeholder":"What you have done — or not done — that you can already see…","hint":"You do not have to know yet. The mission continues when you do.","key":"reflect_midpoint_behaving","isLast":true},{"type":"narrative","locationLabel":"ACT FOUR · THE PATTERN","eyebrow":"Act Four · The Pattern","artId":"shadowPattern","layout":"disc-right","body":["You","begin","to","notice","something."],"bodyAfter":["Calhoun chooses launch-window over data caution. Speed over consensus. Certainty over doubt.","The pattern is subtle. Once seen, impossible to ignore."],"duration":8000,"variants":{"staying_curious":{"bodyAfter":["Hale chooses control over ambiguity. Speed over consensus. Certainty over doubt.","You had already half-seen this. Now you can name it."]},"drifting":{"bodyAfter":["Hale chooses control over ambiguity. Speed over consensus. Certainty over doubt.","You realise — quietly — that you have been making the same trade-offs."]}}},{"type":"question","kind":"rating","locationLabel":"Q13 · THINK CRITICALLY","practice":"Think Critically","setup":"A telemetry briefing arrives with a tidy explanation. It is plausible. It is fast. It is exactly what you would prefer to be true.","prompt":"When an explanation feels neat and immediately convincing, I deliberately slow down and look for what it might be hiding.","labels":["Strongly disagree","Rarely","Sometimes","Usually","It is a discipline"],"scoring":[{"think_critically":10},{"think_critically":35},{"think_critically":55},{"think_critically":80},{"think_critically":100}]},{"type":"narrative-scene","locationLabel":"CALHOUN'S OFFICE · LATE","artId":"privateMeet","quote":"\"The flight readiness review is weak. They hesitate. They reschedule. They re-baseline. We don't need more voices. We need a launch.\"","speaker":"Flight Director Bryce Calhoun","layout":"disc-left","duration":9000},{"type":"question","kind":"mc","locationLabel":"Q14 · INFLUENCE EFFORTLESSLY","practice":"Influence Effortlessly","setup":"Calhoun wants you to help him build alignment across the engineering teams. He asks you how.","prompt":"What do you believe is the most effective way to create lasting alignment?","options":[{"copy":"Persuasion through data and analysis.","score":{"influence_effortlessly":65,"think_critically":45}},{"copy":"Authority and clarity — direction beats debate.","score":{"influence_effortlessly":45,"act_decisively":55,"control_bias":60}},{"copy":"Emotional connection — meet people where they live.","score":{"influence_effortlessly":75,"listen_deeply":55,"collaborate_inclusively":45}},{"copy":"Shared ownership — they helped design it, so they help defend it.","score":{"collaborate_inclusively":90,"influence_effortlessly":85,"be_curious":45}},{"copy":"A story — one frame that makes everyone's contribution visible.","score":{"influence_effortlessly":85,"unlock_creativity":60,"future_focused":55}},{"copy":"Repetition — the same clear message delivered the same way until it lands.","score":{"influence_effortlessly":50,"act_decisively":35,"control_bias":30}}]},{"type":"question","kind":"ranking","locationLabel":"Q15 · UNLOCK CREATIVITY","practice":"Unlock Creativity","setup":"You are asked to redesign a launch sequence that is technically sound but politically brittle. It solves the engineering problem and worsens the human one — engineers are exhausted.","prompt":"Rank your approach to redesigning the sequence, from first to last.","items":[{"label":"Generate as many divergent options as possible before narrowing","score":{"unlock_creativity":100,"manage_uncertainty":55}},{"label":"Seek external perspectives from disciplines outside aerospace","score":{"be_curious":90,"collaborate_inclusively":80,"listen_deeply":65}},{"label":"Prototype a small version rapidly and iterate","score":{"unlock_creativity":75,"manage_uncertainty":80,"act_decisively":65}},{"label":"Refine the existing sequence — the bones are sound","score":{"think_critically":50,"unlock_creativity":15}}],"weights":[1,0.65,0.35,0.05]},{"type":"question","kind":"rating","locationLabel":"Q16 · UNLOCK CREATIVITY","practice":"Unlock Creativity","setup":"You stand in front of an empty engineering chalkboard. The brief: a path forward no one has considered.","prompt":"When constraints tighten, my first instinct is to reframe the problem rather than push harder on the old solution.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"unlock_creativity":10},{"unlock_creativity":35},{"unlock_creativity":55},{"unlock_creativity":80},{"unlock_creativity":100}]},{"type":"narrative","locationLabel":"ACT FIVE · THE DIVIDE","eyebrow":"Act Five · The Divide","artId":"alliesWhisper","layout":"disc-left","body":["Your","colleagues","begin","to","question","Calhoun."],"bodyAfter":["Quietly. Carefully. They do not accuse him. They simply ask whether the mission posture has shifted.","Calhoun calls it cold feet."],"duration":8000},{"type":"question","kind":"mc","locationLabel":"Q17 · COLLABORATE INCLUSIVELY","practice":"Collaborate Inclusively","setup":"Three of your closest colleagues are pulling you aside between shifts. They are afraid. They are not wrong. But Calhoun is watching the room.","prompt":"What do you do?","options":[{"copy":"Align them with the Flight Director quickly to keep the team intact.","score":{"influence_effortlessly":50,"collaborate_inclusively":25,"control_bias":40}},{"copy":"Encourage open debate — the dissent is the data.","score":{"collaborate_inclusively":90,"listen_deeply":75,"master_emotions":55}},{"copy":"Mediate between them — surface the assumptions on each side.","score":{"collaborate_inclusively":85,"think_critically":70,"understand_self":55}},{"copy":"Escalate the concerns formally on the record.","score":{"act_decisively":65,"influence_effortlessly":35,"master_emotions":45}},{"copy":"Create a private structure for them to speak safely until I understand the pattern.","score":{"collaborate_inclusively":80,"listen_deeply":65,"embed_practices":55}},{"copy":"Wait — disagreement under pressure rarely produces the truest answer.","score":{"master_emotions":50,"manage_uncertainty":45,"collaborate_inclusively":20}}]},{"type":"question","kind":"rating","locationLabel":"Q18 · COLLABORATE INCLUSIVELY","practice":"Collaborate Inclusively","setup":"You sense the engineers around you self-editing. Smoothing. Withholding the honest fault report.","prompt":"I actively invite people to disagree with me — and I work to make them safer when they do.","labels":["Strongly disagree","Rarely","Sometimes","Usually","It is one of my disciplines"],"scoring":[{"collaborate_inclusively":10},{"collaborate_inclusively":35},{"collaborate_inclusively":55},{"collaborate_inclusively":80},{"collaborate_inclusively":100}]},{"type":"question","kind":"mc","locationLabel":"Q19 · COLLABORATE INCLUSIVELY","practice":"Collaborate Inclusively","setup":"A delegation of subcontractor engineers arrives. They will not speak with Calhoun. They will only speak with you. They look unlike most people in the room.","prompt":"How do you set up the conversation?","options":[{"copy":"In the formal review room — institutional weight signals respect.","score":{"collaborate_inclusively":30,"influence_effortlessly":50,"control_bias":30}},{"copy":"On their terms, in a place they choose, with their own technical leads.","score":{"collaborate_inclusively":95,"listen_deeply":80,"be_curious":65}},{"copy":"Privately, just me and their three leaders, so trust can build first.","score":{"collaborate_inclusively":80,"listen_deeply":70}},{"copy":"I send a representative first to understand the protocols.","score":{"collaborate_inclusively":60,"be_curious":65,"think_critically":45}},{"copy":"Open the meeting — anyone in their group can speak in any order.","score":{"collaborate_inclusively":85,"listen_deeply":60,"master_emotions":50}},{"copy":"Around food. Real food. We eat before we negotiate.","score":{"collaborate_inclusively":90,"master_emotions":60,"unlock_creativity":55}}]},{"type":"narrative-scene","locationLabel":"ACTION CONSOLE · ORDER DELIVERED","artId":"breakingPoint","quote":"\"The contractor refuses our timeline. Halt their payments. Apply pressure. We launch on schedule.\"","speaker":"Flight Director Bryce Calhoun","layout":"disc-right","duration":9000},{"type":"question","kind":"mc","locationLabel":"Q20 · ACT DECISIVELY","practice":"Act Decisively","setup":"The order is given. The room understands the implication — families on the contractor side. Every eye finds yours.","prompt":"You believe the order will cause serious harm. What do you do?","options":[{"copy":"Follow the order — chain of command exists for a reason.","score":{"moral_drift":80,"control_bias":45,"collaborate_inclusively":10}},{"copy":"Challenge it privately, after the room clears.","score":{"influence_effortlessly":55,"master_emotions":65,"act_decisively":45}},{"copy":"Refuse openly, in front of everyone.","score":{"act_decisively":90,"understand_self":70,"influence_effortlessly":45}},{"copy":"Propose an alternative that solves the schedule problem without the harm — right now, in the room.","score":{"unlock_creativity":85,"collaborate_inclusively":70,"act_decisively":70,"moral_drift":-20}},{"copy":"Delay — buy time and re-open the question with new evidence.","score":{"think_critically":55,"manage_uncertainty":50,"moral_drift":15}},{"copy":"Step out of the chain entirely and warn the affected contractor directly.","score":{"act_decisively":80,"master_emotions":50,"influence_effortlessly":40}}]},{"type":"question","kind":"rating","locationLabel":"Q21 · ACT DECISIVELY","practice":"Act Decisively","setup":"There is a moment where waiting another hour will cost more than a wrong call.","prompt":"When a clear trade-off is required, I make the call — and I own it, including what it costs.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"act_decisively":10},{"act_decisively":35},{"act_decisively":55},{"act_decisively":80},{"act_decisively":100}]},{"type":"question","kind":"rating","locationLabel":"Q22 · BE FUTURE-FOCUSED","practice":"Be Future-Focused","setup":"A choice will solve today and create something heavier in the next mission cycle.","prompt":"I weigh the long-term consequences of a decision as seriously as the immediate outcome.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"future_focused":10},{"future_focused":35},{"future_focused":55},{"future_focused":80},{"future_focused":100}]},{"type":"question","kind":"mc","locationLabel":"Q23 · BE FUTURE-FOCUSED","practice":"Be Future-Focused","setup":"A young engineer asks you: \"What are we trying to build, ten years from now, that justifies pushing this hard?\"","prompt":"What is your honest answer?","options":[{"copy":"I focus on this launch. Ten years is a story we tell ourselves.","score":{"future_focused":15,"act_decisively":50}},{"copy":"A program where this decision never has to be made again.","score":{"future_focused":95,"unlock_creativity":65,"think_critically":60}},{"copy":"Stability. A predictable cadence. The freedom that comes from things actually working.","score":{"future_focused":55,"control_bias":45}},{"copy":"People — specifically, more engineers like you, ready to make hard calls well.","score":{"future_focused":90,"collaborate_inclusively":70,"influence_effortlessly":55}},{"copy":"I don't fully know yet. That is part of why I am still here, listening.","score":{"future_focused":65,"be_curious":70,"understand_self":55}},{"copy":"A culture that can disagree without breaking under deadline.","score":{"future_focused":85,"collaborate_inclusively":80,"listen_deeply":55}}]},{"type":"question","kind":"mc","locationLabel":"Q24 · EMBED PRACTICES","practice":"Embed Practices","setup":"At the end of the shift, the corridors empty. You have twenty quiet minutes before sleep.","prompt":"What do you most often do with that time?","options":[{"copy":"Catch up on telemetry I missed — the day is never finished.","score":{"embed_practices":15,"act_decisively":35,"control_bias":25}},{"copy":"Walk in silence — let the day settle on its own.","score":{"embed_practices":80,"master_emotions":70}},{"copy":"Write — what I noticed, what I felt, what I decided badly.","score":{"embed_practices":95,"understand_self":85}},{"copy":"Speak with one person I trust who is not part of this mission.","score":{"embed_practices":80,"collaborate_inclusively":60,"master_emotions":60}},{"copy":"Read something with no obvious purpose — fiction, history, anything else.","score":{"embed_practices":75,"be_curious":70,"unlock_creativity":50}},{"copy":"Sleep — recovery is the practice.","score":{"embed_practices":55,"master_emotions":50}}]},{"type":"narrative","locationLabel":"PRIVATE LOG · LATE","eyebrow":"Act Six · The Realisation","artId":"reckoningMirror","layout":"disc-right","body":["You","review","the","decisions."],"bodyAfter":["The saved telemetry. The silenced concerns. The reframed dissent.","The language of mission discipline becoming the machinery of deadline. Not discipline. Compliance."],"duration":9000},{"type":"question","kind":"short-text","locationLabel":"Q25 · UNDERSTAND SELF","practice":"Understand Self","setup":"A reflection between scenes. Write what you actually feel — not what would sound impressive.","prompt":"Looking back, when did you first sense something was wrong?","placeholder":"A moment, a sentence, a feeling — write it freely…","hint":"1–3 sentences · not scored automatically · used to surface where you notice weak signals"},{"type":"narrative-scene","locationLabel":"CONFRONTATION · CALHOUN'S OFFICE","artId":"confrontation","quote":"\"Schedule requires control, {{firstName}}. Caution is inefficient. You and I want the same thing.\"","speaker":"Flight Director Bryce Calhoun","layout":"disc-left","duration":9000},{"type":"question","kind":"mc","locationLabel":"Q26 · INFLUENCE EFFORTLESSLY","practice":"Influence Effortlessly","setup":"Calhoun is not angry. He is calm. He believes every word. He wants you to walk out of this office as his ally.","prompt":"How do you respond to him — not as strategy, but as influence?","options":[{"copy":"I dismantle his argument logically, piece by piece.","score":{"think_critically":70,"influence_effortlessly":50,"master_emotions":45}},{"copy":"I find the human inside the position and speak to that.","score":{"influence_effortlessly":90,"listen_deeply":70,"master_emotions":65}},{"copy":"I tell him what he is becoming, gently and without contempt.","score":{"influence_effortlessly":85,"understand_self":65,"master_emotions":75}},{"copy":"I ask him three questions he can't answer without revealing himself.","score":{"influence_effortlessly":80,"think_critically":75,"be_curious":60}},{"copy":"I refuse the false alliance openly and walk out.","score":{"act_decisively":80,"influence_effortlessly":40,"understand_self":60}},{"copy":"I sit with him in silence until the silence does the work.","score":{"influence_effortlessly":70,"master_emotions":80,"listen_deeply":75}}]},{"type":"question","kind":"rating","locationLabel":"Q27 · INFLUENCE EFFORTLESSLY","practice":"Influence Effortlessly","setup":"A test that lives outside this assessment too: how others come to trust your judgement.","prompt":"People I work with adopt my recommendations because of trust and clarity — not because of position, volume, or pressure.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"influence_effortlessly":10},{"influence_effortlessly":35},{"influence_effortlessly":55},{"influence_effortlessly":80},{"influence_effortlessly":100}]},{"type":"question","kind":"rating","locationLabel":"Q28 · MASTER EMOTIONS","practice":"Master Emotions","setup":"A confrontation just ended. Your hands are still steady, but something is moving underneath.","prompt":"In high-stress moments, I can recognise what I am feeling, name it, and stay engaged with the situation.","labels":["Strongly disagree","Rarely","Sometimes","Usually","Almost always"],"scoring":[{"master_emotions":10},{"master_emotions":35},{"master_emotions":55},{"master_emotions":80},{"master_emotions":100}]},{"type":"question","kind":"mc","locationLabel":"Q29 · UNDERSTAND SELF","practice":"Understand Self","setup":"A trusted colleague tells you: \"You become more controlling when you are scared. I don't think you see it.\"","prompt":"What is your honest first reaction?","options":[{"copy":"Defensive — I want to explain why she's wrong.","score":{"understand_self":25,"master_emotions":30}},{"copy":"Curious — I want her to tell me the three most recent examples.","score":{"understand_self":95,"be_curious":80,"master_emotions":65}},{"copy":"Grateful — but unsure whether to believe it yet.","score":{"understand_self":75,"master_emotions":55}},{"copy":"I already knew. I just hadn't admitted it.","score":{"understand_self":90,"embed_practices":55,"master_emotions":60}},{"copy":"Quietly hurt — I will sit with it before I respond.","score":{"understand_self":70,"master_emotions":65}},{"copy":"I dismiss it — she doesn't see the pressure I am under.","score":{"understand_self":10,"control_bias":50,"moral_drift":25}}]},{"type":"question","kind":"rating","locationLabel":"Q30 · LISTEN DEEPLY","practice":"Listen Deeply","setup":"In conversations that matter, you can choose to listen for words — or for everything else.","prompt":"I listen for what is unsaid — tone, silence, what people avoid — as carefully as I listen for what is said.","labels":["Strongly disagree","Rarely","Sometimes","Usually","It is a discipline"],"scoring":[{"listen_deeply":10},{"listen_deeply":35},{"listen_deeply":55},{"listen_deeply":80},{"listen_deeply":100}]},{"type":"narrative","locationLabel":"ACT SEVEN · THE FINAL CALCULATION","eyebrow":"Act Seven · The Final Calculation","artId":"dividedChamber","layout":"disc-left","body":["The","go/no-go","is","imminent."],"bodyAfter":["Calhoun moves to push through despite the new fault signature.","You must choose your position. The launch window closes in six minutes."],"duration":7500},{"type":"question","kind":"mc","locationLabel":"Q31 · ACT DECISIVELY","practice":"Act Decisively","setup":"The room is full. Decision in five minutes. You do not get to abstain.","prompt":"What do you do?","options":[{"copy":"Support Calhoun — schedule matters above all.","score":{"control_bias":100,"moral_drift":80,"influence_effortlessly":25}},{"copy":"Oppose him openly — the math has to be honest.","score":{"act_decisively":85,"understand_self":70,"manage_uncertainty":55}},{"copy":"Seek a compromise between the factions.","score":{"collaborate_inclusively":75,"influence_effortlessly":65,"think_critically":55}},{"copy":"Propose a third structure — replace the binary with a new launch architecture.","score":{"unlock_creativity":90,"future_focused":80,"act_decisively":70}},{"copy":"Step back entirely — let the system resolve it.","score":{"moral_drift":35,"act_decisively":10,"understand_self":25}},{"copy":"Buy time — call for a 24-hour deliberation under a neutral chair.","score":{"manage_uncertainty":65,"think_critically":60,"collaborate_inclusively":50}}]},{"type":"question","kind":"mc","locationLabel":"Q32 · BE CURIOUS","practice":"Be Curious","setup":"The dust settles. You are offered a role on the new Mission Operations leadership team. You will need to keep learning, fast, for the rest of your career.","prompt":"How will you actually do that?","options":[{"copy":"I will surround myself with senior engineers and listen to their summaries.","score":{"be_curious":45,"listen_deeply":50,"collaborate_inclusively":40}},{"copy":"I will deliberately spend time with people whose discipline I do not share.","score":{"be_curious":95,"listen_deeply":70,"collaborate_inclusively":75}},{"copy":"I will read across fields I have no professional reason to study.","score":{"be_curious":85,"unlock_creativity":65,"embed_practices":60}},{"copy":"I will go back to programs I have never been part of and listen before I speak.","score":{"be_curious":90,"listen_deeply":75,"future_focused":50}},{"copy":"I will keep a record of what I got wrong, and review it monthly.","score":{"be_curious":80,"understand_self":80,"embed_practices":85}},{"copy":"I will teach — because teaching exposes what I do not actually understand.","score":{"be_curious":75,"understand_self":65,"influence_effortlessly":60}}]},{"type":"question","kind":"mc","locationLabel":"Q33 · MANAGE UNCERTAINTY","practice":"Manage Uncertainty","setup":"A new fault is emerging in a subsystem you do not understand. You have no precedent. You have no map.","prompt":"What is your first move?","options":[{"copy":"Commit to a clear direction — uncertainty is the enemy of momentum.","score":{"act_decisively":70,"manage_uncertainty":35,"control_bias":45}},{"copy":"Wait for clarity — the wrong action is worse than no action.","score":{"think_critically":35,"manage_uncertainty":20,"act_decisively":10}},{"copy":"Run several small experiments at once — let reality teach me.","score":{"manage_uncertainty":95,"unlock_creativity":80,"act_decisively":60}},{"copy":"Find someone who has lived inside that subsystem and learn before I decide.","score":{"be_curious":85,"listen_deeply":75,"manage_uncertainty":70}},{"copy":"Hold the situation lightly — name what I don't know, out loud.","score":{"manage_uncertainty":90,"understand_self":70,"collaborate_inclusively":60}},{"copy":"Set a deadline by which I must decide, regardless.","score":{"act_decisively":65,"manage_uncertainty":55,"control_bias":25}}]},{"type":"question","kind":"rating","locationLabel":"Q34 · EMBED PRACTICES","practice":"Embed Practices","setup":"The practices that change you are the ones you do when nobody is watching.","prompt":"I have at least one reflection or learning ritual that I have sustained — even when pressure makes it inconvenient.","labels":["No","Briefly","On and off","Mostly","Yes, consistently"],"scoring":[{"embed_practices":10},{"embed_practices":35},{"embed_practices":55},{"embed_practices":80},{"embed_practices":100}]},{"type":"question","kind":"mc","locationLabel":"Q35 · THINK CRITICALLY","practice":"Think Critically","setup":"A clean briefing arrives. Everything fits. The author is competent. The recommendation is exactly what the room wants to hear.","prompt":"What do you do first?","options":[{"copy":"Accept the recommendation — the analyst is good and the team has bandwidth elsewhere.","score":{"think_critically":15,"act_decisively":35}},{"copy":"Ask what evidence would change the conclusion — and whether any of it has been gathered.","score":{"think_critically":95,"be_curious":70}},{"copy":"Identify the assumption that, if wrong, breaks the whole story.","score":{"think_critically":90,"future_focused":55,"manage_uncertainty":55}},{"copy":"Bring in one engineer who will disagree by reflex — and let them.","score":{"think_critically":80,"collaborate_inclusively":75}},{"copy":"Re-frame the question and watch how the recommendation does or does not survive.","score":{"think_critically":85,"unlock_creativity":65}},{"copy":"Run it past my gut and only intervene if it complains.","score":{"think_critically":30,"understand_self":40}}]},{"type":"question","kind":"mc","locationLabel":"Q36 · UNLOCK CREATIVITY","practice":"Unlock Creativity","setup":"A constraint everyone treats as fixed — budget, time, regulation, custom — is the thing keeping you stuck.","prompt":"How do you most often work with constraints like that?","options":[{"copy":"I respect them and find efficiency within.","score":{"unlock_creativity":25,"think_critically":50}},{"copy":"I ignore them and design what is actually needed first, then negotiate.","score":{"unlock_creativity":90,"act_decisively":65,"influence_effortlessly":60}},{"copy":"I treat them as design material and let them shape the solution in surprising ways.","score":{"unlock_creativity":95,"future_focused":60,"manage_uncertainty":65}},{"copy":"I invite the people enforcing the constraint into the redesign.","score":{"unlock_creativity":80,"collaborate_inclusively":85,"influence_effortlessly":65}},{"copy":"I find the original reason the constraint exists — then test whether it still applies.","score":{"unlock_creativity":85,"think_critically":80,"be_curious":75}},{"copy":"I look for analogies in completely unrelated domains.","score":{"unlock_creativity":90,"be_curious":85}}]},{"type":"twist","locationLabel":"TRANSMISSION · OUTBOUND","body":["The intercom flickers on, unintended.","The review board is speaking. Not about Calhoun. About <em>you</em>.","Your recommendations. Your decisions. Your silence when it mattered.","Calhoun turns. Smiles."],"quote":"\"You still think this was my mission? Every step — you justified it.\"","speaker":"Flight Director Bryce Calhoun","variants":{"drifting":{"body":["The transmission flickers.","Council members are speaking. Not about Hale. About <em>you</em>.","Your recommendations. Your composure. The way the harder calls became easier each time.","Hale turns. Smiles. He knew."],"quote":"\"You still think this was my strategy? You were the design. Every step — you justified it.\""},"resisting_hale":{"body":["The transmission flickers.","Council members are speaking. Not about Hale. About <em>you</em>.","Your refusals. Your questions. The moments you would not pretend.","Hale turns. The smile does not arrive."],"quote":"\"You were never mine. I should have seen it earlier.\""}},"duration":11000},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 01 / 04","eyebrow":"Closing reflection · Strengths","intro":"Before the result — four quiet questions. Write only what is true.","prompt":"In which moment of this mission did you feel <em>most like yourself</em>? Where did your real strength show up?","placeholder":"Name the scene, the choice, the feeling…","key":"reflect_strengths"},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 02 / 04","eyebrow":"Closing reflection · Beliefs","prompt":"Which <em>belief</em> of yours was tested by this mission — about people, schedule, or yourself?","placeholder":"A belief you held coming in, that has shifted or been confirmed…","key":"reflect_beliefs"},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 03 / 04","eyebrow":"Closing reflection · Mindset","prompt":"What <em>mindset shift</em> — if you made it — would change how you act under pressure?","placeholder":"From X to Y…","key":"reflect_mindset"},{"type":"end-reflection","locationLabel":"CLOSING REFLECTION · 04 / 04","eyebrow":"Closing reflection · Behaviour","prompt":"Which single <em>skill or behaviour</em> — if you built it deliberately over the next ninety days — would change everything?","placeholder":"The one practice you would commit to…","key":"reflect_behaviour"},{"type":"twist","locationLabel":"REFRAME · BEFORE THE RESULT","body":["This mission was never about whether you were a hero or a villain.","It was about something more useful:","How easily good intentions <em>drift</em> under deadline pressure.","How quickly engineering becomes politics.","How subtly clarity becomes certainty."],"quote":"And how much strategic capability depends on the ability to notice yourself before the pattern becomes the path.","speaker":"Reading your result","duration":11000},{"type":"results-launch"}],"archetypes":{"reactive_defender":{"name":"The First Responder","band":"Strategic Infancy","headline":"You care about protecting the mission — but deadline pressure is driving more of your decisions than you realise.","body":"Your result suggests that when stakes rise, your attention narrows fast. You may move into reaction, urgency, or defence before you have understood what is happening. You are committed and action-oriented — but the same energy that makes you formidable in a crisis can make you blind to the pattern beneath it. You may respond to fault signatures rather than root causes, miss weak telemetry signals, or confuse motion with progress.","risk":"Your risk is not lack of effort. It is pressure-led action. You may be protecting the mission while reinforcing the very patterns that weaken it.","focus":"Start at Level 1 — <em>Deepen Self-Awareness</em>. Notice your pressure patterns. Name your triggers. Build a pause before reacting. Separate fact from interpretation. Ask, \"What am I not seeing yet?\"","next":"Your first breakthrough is likely to come from seeing your own operating system more clearly — before you change anything else."},"tactical_survivor":{"name":"The Engineer in the Trenches","band":"Tactical Survivor","headline":"You can handle pressure — but your problem-solving may be too anchored in the immediate console.","body":"You are capable, practical, and effective in difficult shifts. You make decisions, keep momentum, and solve immediate faults. Your result suggests, though, that short-term demands may be crowding out longer-term mission design. You may prioritise control over understanding, optimise for delivery rather than direction, and carry too much yourself.","risk":"Your risk is tactical over-functioning. You may become so good at surviving the current sim that you unintentionally normalise crisis as the operating model.","focus":"Strengthen Level 3 — <em>Develop Strategic Capabilities</em>. Focus on future-orientation, creative options, and acting well in uncertainty. Move from \"What needs fixing now?\" to \"What future are we creating through this decision?\"","next":"Your growth edge is widening the time horizon you actually think in — from this shift, to this decade of missions."},"hidden_drifter":{"name":"The Compromised Trajectory","band":"Hidden Drift","headline":"You are more strategic than most — but your blindspots emerge precisely when you feel most certain.","body":"You are thoughtful, capable, and likely well-intentioned. You can see complexity, make decisions, and influence others. But your result suggests a subtle risk: under deadline pressure, your strengths can distort. Clarity becomes certainty. Decisiveness becomes control. Conviction becomes justification. Calm becomes detachment. This is the most psychologically important result because it mirrors how strategic drift happens in real mission environments — not through incompetence, but through capable people making apparently reasonable choices under pressure.","risk":"Your risk is <em>justified drift</em>. You may continue making decisions that each seem defensible while the wider pattern moves quietly away from your stated values.","focus":"Work across Levels 1 and 2 together — <em>Deepen Self-Awareness</em> and <em>Cultivate Open-Mindedness</em>. Notice yourself under pressure. Listen most carefully when you disagree. Test the assumptions you would rather keep. Invite challenge. Watch the moment when \"necessary\" becomes a dangerous word.","next":"Your fastest development will come from learning to notice earlier — before the trajectory drifts."},"strategic_operator":{"name":"The Mission Controller","band":"Strategic Operator","headline":"You show strong strategic capability and a relatively balanced pattern under pressure.","body":"Your result suggests you can remain clear, reflective, and effective in complex situations. You likely balance action with thought, confidence with humility, and direction with collaboration. Composure on the loop, thoughtful decisions, openness, alignment, and awareness of consequence are all visible in your pattern.","risk":"Your risk is not capability — it is consistency. Under enough deadline pressure, even strong operators drift into old patterns. The opportunity is to make your strategic capability more reliable, more repeatable, and more visible to others.","focus":"Strengthen Level 4 — <em>Scale Your Impact</em>. Decision quality, stakeholder alignment, influence without over-control, collaboration under tension. Turning strategic insight into action that travels.","next":"Your growth edge is becoming more conscious — and more deliberate — about the impact you already have."},"force_multiplier":{"name":"The Architect of Apollo","band":"Strategic Force Multiplier","headline":"You do not just think strategically. You increase the strategic capacity of the program around you.","body":"Your result suggests a highly integrated strategic profile. You can stay aware of yourself under pressure, regulate emotion without disconnecting from consequence, listen deeply, think critically, generate options in uncertainty, decide with courage and humility, and influence without domination. You hold complexity without collapsing into confusion or control.","risk":"Your risk is <em>over-reliance</em>. Others may look to you for clarity, judgement, and steadiness. Over time, that can quietly create dependency — unless you intentionally build capability in the program around you.","focus":"Your next level is multiplication. Develop strategic capability in others. Design decision systems. Build collective intelligence. Create the conditions for others to hold uncertainty without panic.","next":"Your development edge is to become less necessary — by making the program more strategically capable."}},"secondaryPatterns":{"architect_of_order":{"name":"The Procedure Hawk","headline":"Drawn to checklist, control, and decisive action.","body":"You are highly effective on the loop. But unchecked, your strength becomes rigidity. You may begin to mistake disagreement for sloppiness, ambiguity for failure, and speed for strategy."},"the_justifier":{"name":"The Necessary Risks","headline":"At risk of rationalising questionable engineering calls when the deadline feels important enough.","body":"This does not mean you lack values. It means your values can become vulnerable when launch-window, loyalty, or political pressure enters the room."},"the_calm_blade":{"name":"The Cool Console","headline":"Composed in moments that unsettle others on the loop.","body":"That composure is valuable. But there is a fine line between regulation and emotional distance. Your edge is to remain calm without becoming disconnected from human consequence."},"the_consensus_seeker":{"name":"The Coalition Builder","headline":"You create inclusion and invite voice — but may delay difficult go/no-go calls.","body":"Your development edge is to preserve collaboration while becoming more decisive when the window closes."},"the_decisive_commander":{"name":"The Cowboy","headline":"You move quickly and bring momentum — but your speed may narrow the field of telemetry.","body":"Your edge is to slow down just enough to hear what the system is trying to tell you."},"vision_under_strain":{"name":"The Visionary Cracking","headline":"You see beyond the immediate launch, but pressure may disrupt your steadiness on the loop.","body":"Your edge is to build inner stability so your vision survives contact with reality."}},"riskCopy":{"control_bias":{"name":"Authority Reflex","low":"You appear able to pursue clarity without defaulting to command.","mod":"You may sometimes overvalue speed, certainty, or chain of command when pressure rises.","high":"You may be at risk of mistaking <em>command for strategy</em>. This can make you decisive — but it may also reduce listening, creativity, and trust on the loop.","q":"Where might you be calling something <em>alignment</em> when it is actually compliance?"},"moral_drift":{"name":"Schedule Drift","low":"Your responses suggest a relatively strong ability to keep means and ends connected.","mod":"You may occasionally justify difficult engineering actions when the launch window feels important enough.","high":"You may be vulnerable to rationalising harmful choices if they appear necessary for the schedule.","q":"At what point does a necessary compromise become a betrayal of the mission itself?"},"detachment_pressure":{"name":"Cold Console","low":"You appear able to stay connected to human consequence while under pressure.","mod":"Your composure is a strength, but it may sometimes become distance.","high":"You may remain calm in ways others on the loop experience as emotionally unavailable, overly rational, or disconnected from impact.","q":"How do you stay steady without becoming unreachable?"}},"nextSteps":{"reactive_defender":[{"icon":"pause","title":"The five-second hold","body":"Before responding to a fault signature, give yourself five seconds. Notice what your body wants to do, then choose what to do.","test":"Try for 7 shifts. Track each time you used it."},{"icon":"journal","title":"A nightly two-line log","body":"Each evening write: \"Today I noticed…\" and \"Tomorrow I will…\". Build the muscle of self-observation.","test":"Do this for 21 days, then re-read the lot."},{"icon":"mirror","title":"Ask one colleague","body":"Ask one trusted colleague: \"When pressure rises, what do you see me become on the loop?\" Listen without defending.","test":"One question, one person, this week."},{"icon":"question","title":"Replace \"should\" with \"if\"","body":"Notice your \"shoulds\" — they are usually pressure speaking. Reframe to \"if I did this, what would happen?\" Re-open the choice.","test":"Count your \"shoulds\" for one day. Reframe three."}],"tactical_survivor":[{"icon":"horizon","title":"The 10-year question","body":"On any non-trivial decision, ask: \"What does this look like in a decade of missions?\" Forces you out of fire-fighting and into direction.","test":"Apply to your next three meaningful decisions."},{"icon":"experiment","title":"Run one strategic experiment","body":"Pick one current fault. Generate four genuinely different solutions before settling on one. Build option-fluency.","test":"One fault, four options, this week."},{"icon":"doors","title":"Future-back planning","body":"Describe in detail what good looks like 18 months from now. Then walk backwards: what decision today would matter then?","test":"90 minutes, a single page, by Friday."},{"icon":"reframe","title":"Trade urgency for importance","body":"For one week, mark every task as either urgent OR important. Notice the ratio. Notice what does not survive scrutiny.","test":"Audit for 5 days. Drop three urgent-not-important items."}],"hidden_drifter":[{"icon":"notice","title":"The drift word audit","body":"Notice when you use words like \"necessary\", \"no choice\", \"this once\". Each is a possible drift signal. Pause, name, examine.","test":"Track for two weeks. Bring the list to your coach."},{"icon":"invite","title":"Invite your strongest dissenter","body":"Identify the engineer most likely to disagree with you. Invite them into a real decision. Treat their resistance as data.","test":"One conversation, this month. Document what shifted."},{"icon":"mirror","title":"The 360 sentence","body":"Ask three colleagues: \"What is one thing about my pattern under pressure that I probably do not see?\" Listen without explaining.","test":"Three people, one question, no defending."},{"icon":"pause","title":"Slow down on the certain ones","body":"When a call feels obvious, you are most at risk. Apply a 24-hour rule to anything you are certain about.","test":"Use the rule three times this month."}],"strategic_operator":[{"icon":"multiply","title":"Develop one other person","body":"Choose one engineer in your orbit. Help them build a strategic muscle they currently lack. Multiplication begins with one.","test":"Name the person. Name the muscle. Begin."},{"icon":"decide","title":"Make decisions more visible","body":"When you make a meaningful call, share publicly what you considered and what you weighed. Make the strategy legible.","test":"Try this on three decisions this month."},{"icon":"reframe","title":"Sharpen the consequential 20%","body":"Identify the 20% of your decisions that drive 80% of mission outcomes. Concentrate your thinking time there. Delegate or systematise the rest.","test":"Map your decisions for a week. Re-balance time."},{"icon":"experiment","title":"Pick one risk to deliberately reduce","body":"Look at your three risk overlays. Choose the one closest to becoming a real constraint. Design a small practice to soften it.","test":"One overlay, one practice, 30 days."}],"force_multiplier":[{"icon":"multiply","title":"Design a decision system","body":"Create a clear template for how strategic decisions get made in your program — owner, evidence, options, trade-offs, review. Replicable, not heroic.","test":"Build the v1 template. Apply to your next big call."},{"icon":"invite","title":"Build the bench","body":"Identify three engineers who could become the next layer of strategic capability. Invest in them deliberately, with regular feedback and stretch decisions.","test":"Three names. One conversation each, this month."},{"icon":"mirror","title":"Make yourself less necessary","body":"In every meeting this month, ask: \"Could someone else here have led this?\" Then arrange for that to be true next time.","test":"One month of audit. Hand off two recurring meetings."},{"icon":"horizon","title":"Author the long brief","body":"Write a short paper on the strategic capability you want your wider program to have in three years. Use it as a north star — share, debate, refine.","test":"One page. Share with three trusted readers."}]},"imageMap":{"archetypeDir":"images/skin-apollo/","scene":{"councilChamber":"images/skin-apollo/scene-mocr.png","fracturedCity":"images/skin-apollo/scene-cape-launchpad.png","convoyArc":"images/skin-apollo/scene-telemetry-dropout.png","privateMeet":"images/skin-apollo/scene-flight-director-office.png","breakingPoint":"images/skin-apollo/scene-action-console.png","confrontation":"images/skin-apollo/scene-confrontation.png","twinSuns":"images/skin-apollo/scene-katherine-office.png","summonsHerald":"images/skin-apollo/scene-mocr-overview.png","chaoticCouncil":"images/skin-apollo/scene-computers-room.png","aftermathMedbay":"images/skin-apollo/scene-sim-debrief.png","shadowPattern":"images/skin-apollo/scene-shadow-pattern.png","alliesWhisper":"images/skin-apollo/scene-allies-whisper.png","reckoningMirror":"images/skin-apollo/scene-reckoning.png","dividedChamber":"images/skin-apollo/scene-go-nogo.png"}}};

